// This program implements a sorting algorithm that can be evolved to adapt to different data patterns

use std::cmp::Ordering;

// EVOLVE-BLOCK-START
// Initial implementation: Simple quicksort
// This can be evolved to:
// - Hybrid algorithms (introsort, timsort-like)
// - Adaptive pivot selection
// - Special handling for nearly sorted data
// - Switching to different algorithms based on data characteristics

pub fn adaptive_sort<T: Ord + Clone>(arr: &mut [T]) {
    if arr.len() < 2 { return; }
    if arr.windows(2).all(|w| w[0] <= w[1]) { return; }
    if arr.windows(2).all(|w| w[0] >= w[1]) { return arr.reverse(); }
    quicksort(arr);
}

fn quicksort<T: Ord + Clone>(mut arr: &mut [T]) {
    while arr.len() > 20 {
        let p = partition(arr);
        let (left, right) = arr.split_at_mut(p);
        if left.len() < right.len() {
            quicksort(left);
            arr = &mut right[1..];
        } else {
            quicksort(&mut right[1..]);
            arr = left;
        }
    }
    for i in 1..arr.len() {
        let mut j = i;
        while j > 0 && arr[j - 1] > arr[j] {
            arr.swap(j, j - 1);
            j -= 1;
        }
    }
}

fn partition<T: Ord + Clone>(arr: &mut [T]) -> usize {
    let (n, mid, last) = (arr.len(), arr.len() / 2, arr.len() - 1);
    if arr[mid] < arr[0] { arr.swap(0, mid); }
    if arr[last] < arr[0] { arr.swap(0, last); }
    if arr[last] < arr[mid] { arr.swap(mid, last); }
    arr.swap(mid, last);
    let pivot = arr[last].clone();
    let mut i = 0;
    for j in 0..last {
        if arr[j] <= pivot {
            arr.swap(i, j);
            i += 1;
        }
    }
    arr.swap(i, last);
    i
}
